import { useVoucherInitData } from './useVoucherInitData';
import { isPermissionsLocalModeActive } from '../dev/isPermissionsLocalMode';

const LOCAL_LIST_ACTIONS = {
  canCreate: true,
  canApprove: true,
  canUpdate: true,
  canPrint: true,
  canViewLedger: true,
} as const;

/**
 * List page toolbar flags — same init-data / formPermissions as create form (`voucher-permissions.md`).
 * Pass the create formName (e.g. `create-cash-receipt`), not the list formName.
 *
 * Local: `VITE_PERMISSIONS_LOCAL_MODE=true` or dev server (unless `=false`).
 */
export function useVoucherListActions(createFormName: string) {
  const { formPermissions, loading } = useVoucherInitData(createFormName);

  if (isPermissionsLocalModeActive()) {
    return {
      loading: false,
      formPermissions: formPermissions ?? null,
      canCreate: LOCAL_LIST_ACTIONS.canCreate,
      canApprove: LOCAL_LIST_ACTIONS.canApprove,
      canUpdate: LOCAL_LIST_ACTIONS.canUpdate,
      canPrint: LOCAL_LIST_ACTIONS.canPrint,
      canViewLedger: LOCAL_LIST_ACTIONS.canViewLedger,
    };
  }

  return {
    loading,
    formPermissions: formPermissions ?? null,
    canCreate: formPermissions?.canCreate ?? false,
    canApprove: formPermissions?.canApprove ?? formPermissions?.canUnpost ?? false,
    canUpdate: formPermissions?.canUpdate ?? false,
    canPrint: formPermissions?.canPrint ?? false,
    canViewLedger: formPermissions?.canViewLedger ?? false,
  };
}
